mapper.insert:
INSERT INTO MATERIALS(MATERIAL_ID
                    , MATERIAL_CODE
                    , MATERIAL_NAME
                    , MATERIAL_TYPE
                    , COST_PRICE
                    , SELLING_PRICE
                    , IMAGE_FILE_ID
                    , DETAILS
                    , CREATED_BY)
               VALUES(SEQ_MATERIAL.NEXTVAL
                    , #{materialType} || '-' || LPAD(SEQ_MATERIAL.CURRVAL, 3, '0')
                    , #{materialName}
                    , #{materialType}
                    , #{costPrice}
                    , #{sellingPrice}
                    , #{imageFileId}
                    , #{details}
                    , #{createdBy})

mapper.update:
    	UPDATE MATERIALS
		   SET MATERIAL_CODE = #{materialType} || SUBSTR(MATERIAL_CODE, 3)
		     , MATERIAL_NAME = #{materialName}
		     , MATERIAL_TYPE = #{materialType}
		     , COST_PRICE    = #{costPrice}
		     , SELLING_PRICE = #{sellingPrice}
		     , IMAGE_FILE_ID = #{imageFileId}
		     , DETAILS       = #{details}
		     , UPDATED_BY    = #{updatedBy}
		     , UPDATED_AT    = SYSDATE
		 WHERE MATERIAL_ID   = #{materialId}
		   AND STATUS 		!= 'INACTIVE'
